// =====================
// Thresholds (no magic numbers)
// =====================
const BUY_UP_PROB_THRESHOLD    = 0.56;
const BUY_DOWN_PROB_THRESHOLD  = 0.44;
const BUY_UP_EDGE_THRESHOLD    = 0.04;
const BUY_DOWN_EDGE_THRESHOLD  = -0.04;

// Indicator weights (must sum to 1)
const W_RETURN_15M = 0.15;
const W_RETURN_1H  = 0.25;
const W_RETURN_4H  = 0.25;
const W_RSI        = 0.15;
const W_EMA_CROSS  = 0.10;
const W_MACD_HIST  = 0.10;

// Logistic scale: direction_score ∈ [-1,1] → sigmoid(score * SCORE_SCALE)
const SCORE_SCALE = 1.0;

const sigmoid = (x) => 1 / (1 + Math.exp(-x));
const clamp   = (v, lo, hi) => Math.max(lo, Math.min(hi, v));

// =====================
// Event-scope features
// =====================
const klines  = ctx.underlying.klines;
const closes  = klines.map(k => k.close);
const highs   = klines.map(k => k.high);
const lows    = klines.map(k => k.low);
const n       = closes.length;

// ATR(14) Wilder smoothing
let atr = 0;
if (n >= 15) {
  const trs = [];
  for (let i = 1; i < n; i++) {
    const tr = Math.max(highs[i]-lows[i], Math.abs(highs[i]-closes[i-1]), Math.abs(lows[i]-closes[i-1]));
    trs.push(tr);
  }
  let atrVal = trs.slice(0, 14).reduce((a, b) => a + b, 0) / 14;
  for (let i = 14; i < trs.length; i++) atrVal = (atrVal * 13 + trs[i]) / 14;
  atr = atrVal;
}
const currentPrice = closes[n - 1];
const atrRatio     = currentPrice > 0 ? atr / currentPrice : 0.02;
const atrScale     = atrRatio > 0 ? atrRatio : 0.02;

// Price returns
const lastBar = klines[n - 1];
const ret15m  = (lastBar.close - lastBar.open) / lastBar.open;
const ret1h   = n >= 2 ? (closes[n-1] - closes[n-2]) / closes[n-2] : 0;
const ret4h   = n >= 5 ? (closes[n-1] - closes[n-5]) / closes[n-5] : 0;

// RSI(14)
const rsiVal = ctx.helpers.rsi(closes, 14);

// EMA(12) and EMA(26)
const ema12Arr = ctx.helpers.emaArray(closes, 12);
const ema26Arr = ctx.helpers.emaArray(closes, 26);
const ema12    = ema12Arr.at(-1);
const ema26    = ema26Arr.at(-1);
const emaCross = ema12 - ema26;

// MACD histogram = MACD_line - Signal(9)
const macdLine  = ema12Arr.map((v, i) => v - ema26Arr[i]);
const signalArr = ctx.helpers.emaArray(macdLine, 9);
const macdHist  = macdLine.at(-1) - signalArr.at(-1);

// Normalize signals to [-1, 1]
const sig15m  = clamp(ret15m / atrScale,                      -1, 1);
const sig1h   = clamp(ret1h  / atrScale,                      -1, 1);
const sig4h   = clamp(ret4h  / (atrScale * 2),                -1, 1);
const sigRsi  = clamp((rsiVal - 50) / 20,                     -1, 1);
const sigEma  = clamp(emaCross / currentPrice / atrScale,     -1, 1);
const sigMacd = clamp(macdHist / currentPrice / (atrScale * 0.5), -1, 1);

// direction_score ∈ [-1, 1]
const direction_score = clamp(
  sig15m * W_RETURN_15M +
  sig1h  * W_RETURN_1H  +
  sig4h  * W_RETURN_4H  +
  sigRsi * W_RSI        +
  sigEma * W_EMA_CROSS  +
  sigMacd * W_MACD_HIST,
  -1, 1
);

// predicted_prob_up via logistic mapping
const predicted_prob_up = sigmoid(direction_score * SCORE_SCALE);

// =====================
// Per-market output
// =====================
return ctx.markets.map(market => {
  try {
    if (market.closed || market.hoursToExpiry < 0) {
      return { question: market.question, decision: "hold", action: "HOLD", reason: "closed or expired" };
    }

    const upOutcome = market.outcomes.find(o => o.label.toLowerCase() === 'up');
    if (!upOutcome) {
      return { question: market.question, decision: "hold", action: "HOLD", reason: "no Up outcome found" };
    }

    const market_prob_up = upOutcome.price;
    const edge = predicted_prob_up - market_prob_up;

    let action;
    let holdReason = null;
    if (predicted_prob_up >= BUY_UP_PROB_THRESHOLD && edge >= BUY_UP_EDGE_THRESHOLD) {
      action = "BUY_UP";
    } else if (predicted_prob_up <= BUY_DOWN_PROB_THRESHOLD && edge <= BUY_DOWN_EDGE_THRESHOLD) {
      action = "BUY_DOWN";
    } else {
      action = "HOLD";
      const directionClear = predicted_prob_up >= BUY_UP_PROB_THRESHOLD || predicted_prob_up <= BUY_DOWN_PROB_THRESHOLD;
      holdReason = directionClear ? "edge 不足" : "方向不够明确";
    }

    return {
      question:        market.question,
      decision:        action === "HOLD" ? "hold" : "buy",
      action,
      holdReason,
      raw_indicators: {
        ret15m,
        ret1h,
        ret4h,
        rsi14:     rsiVal,
        ema12,
        ema26,
        ema_cross: emaCross,
        macd_hist: macdHist,
        atr_ratio: atrRatio,
      },
      normalized_signals: { sig15m, sig1h, sig4h, sigRsi, sigEma, sigMacd },
      direction_score,
      predicted_prob_up,
      market_prob_up,
      edge,
      spotPrice:     currentPrice,
      expiryDate:    market.expiryDate,
      hoursToExpiry: market.hoursToExpiry,
    };
  } catch (err) {
    return { question: market.question, decision: "hold", action: "HOLD", reason: String(err) };
  }
});
